metadata.plantUmlData:
{
  "data": "@startuml
hide circle
skinparam linetype ortho
skinparam nodesep 60
skinparam ranksep 60
skinparam roundcorner 5
skinparam classAttributeIconSize 0

' --- 01 & 02: Core Identity ---
package "Core Identity" #E3F2FD {
  entity "departments" {
    + id : int(4)
    - name : varchar(150)
  }

  entity "users" {
    + id : uuid(36)
    ~ department_id : int(4) <<FK>>
    - email : varchar(255)
    - first_name_th : varchar(100)
    - status : varchar(50)
  }
}

' --- 14: E-Office & Docs ---
package "E-Office & Document" #FFF3E0 {
  entity "eoffice_documents" {
    + id : uuid(36)
    ~ sender_department_id : int(4) <<FK>>
    - doc_no : varchar(50)
    - title : varchar(255)
    - status : varchar(50)
  }

  entity "documents" {
    + id : uuid(36)
    ~ owner_user_id : uuid(36) <<FK>>
    - title : varchar(255)
  }
}

' --- 17: Academic Management ---
package "Academic Management" #E8F5E9 {
  entity "academic_rooms" {
    + id : uuid(36)
    - room_code : varchar(50)
    - room_type : varchar(50)
  }

  entity "academic_courses" {
    + id : uuid(36)
    - course_code : varchar(50)
    - name_th : varchar(255)
  }

  entity "academic_teaching_loads" {
    + id : uuid(36)
    ~ user_id : uuid(36) <<FK>>
    ~ course_id : uuid(36) <<FK>>
    ~ room_id : uuid(36) <<FK>>
    - section : varchar(50)
  }
}

' --- Operations (ERP, Project, IT) ---
package "Operations (ERP, Project, IT)" #FFFDE7 {
  entity "erp_purchase_requests" {
    + id : uuid(36)
    ~ requester_user_id : uuid(36) <<FK>>
    - pr_no : varchar(50)
    - total_amount : numeric(15,2)
  }

  entity "projects" {
    + id : uuid(36)
    ~ owner_user_id : uuid(36) <<FK>>
    - name : varchar(255)
    - status : varchar(50)
  }

  entity "helpdesk_tickets" {
    + id : uuid(36)
    ~ requester_user_id : uuid(36) <<FK>>
    - title : varchar(255)
    - status : varchar(50)
  }
}

' --- 15: HR System ---
package "HR System" #FCE4EC {
  entity "hr_employee_profiles" {
    + id : uuid(36)
    ~ user_id : uuid(36) <<FK>>
    - employee_type : varchar(50)
    - hire_date : date(4)
  }
}

' --- 18: Facility Booking ---
package "Facility Booking" #F3E5F5 {
  entity "meeting_rooms" {
    + id : uuid(36)
    - name : varchar(150)
    - capacity : int(4)
  }

  entity "room_bookings" {
    + id : uuid(36)
    ~ user_id : uuid(36) <<FK>>
    ~ room_id : uuid(36) <<FK>>
    - title : varchar(255)
    - start_time : timestamptz(8)
  }
}

' ================= Relationships (Foreign Keys) ================= '
' Core Relations
departments ||--o{ users
departments ||--o{ eoffice_documents

' Users connecting to Subsystems
users ||--|| hr_employee_profiles
users ||--o{ documents
users ||--o{ academic_teaching_loads
users ||--o{ room_bookings
users ||--o{ erp_purchase_requests
users ||--o{ projects
users ||--o{ helpdesk_tickets

' Intra-Module Relations
academic_courses ||--o{ academic_teaching_loads
academic_rooms ||--o{ academic_teaching_loads
meeting_rooms ||--o{ room_bookings

@enduml",
  "format": "svg"
}
